103→/// Generate a random integer, biased toward boundary values.
104→fn generate_int(rng: &mut impl Rng) -> Value {
105→    let choice: u8 = rng.random_range(0..10);
106→    let n = match choice {
107→        0 => 0,
108→        1 => 1,
109→        2 => -1,
110→        3 => i64::MAX,
111→        4 => i64::MIN,
112→        _ => rng.random_range(-1000..=1000),
113→    };
114→    json!(n)
115→}
116→
117→/// Generate a random float, biased toward boundary values.
118→///
119→/// Includes integer values in the distribution since TypeScript's `number`
120→/// type covers both integers and floats.
121→fn generate_float(rng: &mut impl Rng) -> Value {
122→    let choice: u8 = rng.random_range(0..12);
123→    let n: f64 = match choice {
124→        0 => 0.0,
125→        1 => 1.0,
126→        2 => -1.0,
127→        3 => 0.5,
128→        4 => -0.5,
129→        // Include some integer values to cover integer-like branches (e.g. n % 2 === 0)
130→        5 => rng.random_range(-100..=100) as f64,
131→        6 => 2.0,
132→        7 => -2.0,
133→        8 => 10.0,
134→        _ => rng.random_range(-1000.0..1000.0),
135→    };
136→    json!(n)
137→}
138→
139→/// Generate a random string from a small vocabulary plus random characters.
140→fn generate_string(rng: &mut impl Rng) -> Value {
141→    let choice: u8 = rng.random_range(0..10);
142→    let s = match choice {
143→        0 => String::new(),
144→        1 => "hello".to_string(),
145→        2 => "test".to_string(),
146→        3 => " ".to_string(),
147→        4 => "0".to_string(),
148→        5 => "true".to_string(),
149→        6 => "null".to_string(),
150→        _ => {
151→            let len = rng.random_range(1..=20);
152→            (0..len)
153→                .map(|_| rng.random_range(b'a'..=b'z') as char)
154→                .collect()
155→        }
156→    };
157→    json!(s)
158→}
