388→/// Confidence-scored label for error intent classification.
389→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
390→pub struct ErrorIntentLabel {
391→    /// "likely_validation", "likely_runtime", or "unknown"
392→    pub label: String,
393→    /// Confidence score 0.0–1.0
394→    pub confidence: f64,
395→}
396→
397→/// Classify whether a thrown error is a deliberate validation rejection or an
398→/// accidental runtime failure by examining the branch path immediately before the error.
399→///
400→/// Pattern: a guard branch taken=true followed immediately by the error (no intervening
401→/// branches) suggests intentional input rejection. Errors without a preceding guard
402→/// or deep in the branch path are more likely accidental.
403→pub fn classify_error_intent(result: &crate::protocol::ExecuteResult) -> Option<ErrorIntentLabel> {
404→    let error = result.thrown_error.as_ref()?;
405→
406→    // If the frontend already classified this as infrastructure, trust it
407→    if error.error_category.as_deref() == Some("infrastructure") {
408→        return Some(ErrorIntentLabel {
409→            label: "likely_runtime".into(),
410→            confidence: 0.9,
411→        });
412→    }
413→
414→    let branch_path = &result.branch_path;
415→    if branch_path.is_empty() {
416→        // No branch data — can't infer intent
417→        return Some(ErrorIntentLabel {
418→            label: "unknown".into(),
419→            confidence: 0.0,
420→        });
421→    }
422→
423→    // Check the last branch before the error
424→    let last_branch = branch_path.last().unwrap();
425→
426→    // Guard pattern: last branch taken=true, suggesting an if-guard that led to a throw.
427→    // Shallow depth (few branches) + guard = likely validation.
428→    if last_branch.taken && branch_path.len() <= 3 {
429→        return Some(ErrorIntentLabel {
430→            label: "likely_validation".into(),
431→            confidence: 0.7,
432→        });
433→    }
434→
435→    // Deep branch path with error = likely accidental runtime failure
436→    if branch_path.len() > 5 {
437→        return Some(ErrorIntentLabel {
438→            label: "likely_runtime".into(),
439→            confidence: 0.6,
440→        });
441→    }
442→
443→    // Frontend-level classification can help disambiguate
444→    if error.error_category.as_deref() == Some("validation") {
445→        return Some(ErrorIntentLabel {
446→            label: "likely_validation".into(),
447→            confidence: 0.8,
448→        });
449→    }
450→    if error.error_category.as_deref() == Some("runtime") {
451→        return Some(ErrorIntentLabel {
452→            label: "likely_runtime".into(),
453→            confidence: 0.7,
454→        });
455→    }
456→
457→    Some(ErrorIntentLabel {
458→        label: "unknown".into(),
459→        confidence: 0.3,
460→    })
461→}
