468→/// Send a Setup command to the frontend and return the setup_context.
469→async fn send_setup(
470→    frontend: &mut Frontend,
471→    setup_file: &str,
472→    function: &str,
473→    mode: SetupMode,
474→    project_root: Option<String>,
475→) -> Result<Option<serde_json::Value>, ExploreError> {
476→    let response = frontend
477→        .send(ProtoCommand::Setup {
478→            file: setup_file.to_string(),
479→            function: function.to_string(),
480→            mode,
481→            project_root,
482→        })
483→        .await?;
484→    match response.result {
485→        ResponseResult::Setup { setup_context } => Ok(Some(setup_context)),
486→        ResponseResult::Error { message, .. } => {
487→            log::warn!("setup error for {function}: {message}");
488→            Ok(None)
489→        }
490→        other => Err(ExploreError::UnexpectedResponse(format!(
491→            "expected Setup response, got {other:?}"
492→        ))),
493→    }
494→}
