515→/// Explore a single function by generating random inputs and executing them.
516→pub async fn explore_function(
517→    frontend: &mut Frontend,
518→    analysis: &FunctionAnalysis,
519→    config: &ExploreConfig,
520→) -> Result<ObservationOutput, ExploreError> {
521→    let instrument_response = frontend
522→        .send(ProtoCommand::Instrument {
523→            file: config.file.clone(),
524→            function: analysis.name.clone(),
525→            mocks: config.mocks.clone(),
526→            project_root: config.project_root.clone(),
527→        })
528→        .await?;
529→
530→    let instrumentable_line_count = match instrument_response.result {
531→        ResponseResult::Instrument { instrumented, instrumentable_line_count, .. } => {
532→            if !instrumented {
533→                return Err(ExploreError::UnexpectedResponse(
534→                    "instrumentation returned instrumented=false".to_string(),
535→                ));
536→            }
537→            instrumentable_line_count
538→        }
539→        ResponseResult::Error { code, message, .. } => {
540→            return Err(ExploreError::UnexpectedResponse(format!(
541→                "instrument error ({code:?}): {message}"
542→            )));
543→        }
544→        other => {
545→            return Err(ExploreError::UnexpectedResponse(format!(
546→                "expected Instrument response, got {other:?}"
547→            )));
548→        }
549→    };
550→
551→    let mut rng = match config.seed {
552→        Some(seed) => StdRng::seed_from_u64(seed),
553→        None => StdRng::from_os_rng(),
554→    };
555→
556→    // --- Setup lifecycle ---
557→    let has_setup =
558→        config.setup_file.is_some() && frontend_supports(&config.capabilities, "setup");
559→    let per_function_setup = has_setup && config.setup_mode == SetupMode::PerFunction;
560→    let per_execution_setup = has_setup && config.setup_mode == SetupMode::PerExecution;
561→
562→    let mut setup_context: Option<serde_json::Value> = None;
563→
564→    if per_function_setup
565→        && let Some(ref setup_file) = config.setup_file
566→    {
567→        setup_context =
568→            send_setup(frontend, setup_file, &analysis.name, config.setup_mode, config.project_root.clone()).await?;
569→    }
570→
571→    // --- Generator prefetch ---
572→    let has_generators = config
573→        .value_sources
574→        .iter()
575→        .any(|s| matches!(s, ValueSource::CustomGenerator { .. }));
576→    let use_generators = has_generators && frontend_supports(&config.capabilities, "generate");
577→
578→    let mut prefetched = if use_generators {
579→        prefetch_custom_values(&config.value_sources, frontend, config.max_iterations as usize)
580→            .await
581→            .unwrap_or_else(|e| {
582→                log::debug!("prefetch failed, falling back to built-in: {e}");
583→                PrefetchedValues::new()
584→            })
585→    } else {
586→        PrefetchedValues::new()
587→    };
588→
589→    let mut seen_paths: HashSet<u64> = HashSet::new();
590→    let mut all_lines: HashSet<u32> = HashSet::new();
591→    let mut new_path_executions: Vec<ExecutionSummary> = Vec::new();
592→    let mut raw_results: Vec<(Vec<serde_json::Value>, ExecuteResult)> = Vec::new();
593→    let mut iterations: u32 = 0;
594→    let mut path_counts: HashMap<u64, u32> = HashMap::new();
595→    let mut seen_branch_ids: HashSet<u32> = HashSet::new();
596→    let mut discoveries: Vec<(u32, DiscoveryMethod)> = Vec::new();
597→
598→    // --- Float probe phase ---
599→    // Probes consume from the iteration budget, contributing to seen_paths and raw_results.
600→    let float_indices = crate::float_probe::float_param_indices(&analysis.params);
601→    let mut float_probe_results: Vec<crate::float_probe::FloatProbeResult> = Vec::new();
602→    let probe_budget = float_indices.len() * crate::float_probe::PROBE_COUNT * 2;
603→    if !float_indices.is_empty() && probe_budget < config.max_iterations as usize {
604→        for &idx in &float_indices {
605→            let pairs = crate::float_probe::generate_probe_pairs(
606→                &analysis.params,
607→                idx,
608→                crate::float_probe::PROBE_COUNT,
609→                &mut rng,
610→            );
611→            let mut agreements = 0usize;
612→            let mut total_probes = 0usize;
613→            let mut divergent_values = Vec::new();
614→
615→            for (float_inputs, floor_inputs) in pairs {
616→                let float_resp = frontend
617→                    .send(ProtoCommand::Execute {
618→                        function: analysis.name.clone(),
619→                        inputs: float_inputs.clone(),
620→                        mocks: config.mocks.clone(),
621→                        setup_context: setup_context.clone(),
622→                    })
623→                    .await?;
624→
625→                let floor_resp = frontend
626→                    .send(ProtoCommand::Execute {
627→                        function: analysis.name.clone(),
628→                        inputs: floor_inputs,
629→                        mocks: config.mocks.clone(),
630→                        setup_context: setup_context.clone(),
631→                    })
632→                    .await?;
633→
634→                if let (
635→                    ResponseResult::Execute(float_result),
636→                    ResponseResult::Execute(floor_result),
637→                ) = (&float_resp.result, &floor_resp.result) {
638→                    total_probes += 1;
639→
640→                    let fhash = path_hash(float_result, &config.loop_buckets);
641→                    let flhash = path_hash(floor_result, &config.loop_buckets);
642→                    seen_paths.insert(fhash);
643→                    seen_paths.insert(flhash);
644→                    for &line in &float_result.lines_executed {
645→                        all_lines.insert(line);
646→                    }
647→                    for &line in &floor_result.lines_executed {
648→                        all_lines.insert(line);
649→                    }
650→
651→                    if crate::float_probe::executions_agree(float_result, floor_result) {
652→                        agreements += 1;
653→                    } else if let Some(v) = float_inputs.get(idx).and_then(|v| v.as_f64()) {
654→                        divergent_values.push(v);
655→                    }
656→
657→                    raw_results.push((float_inputs.clone(), (**float_result).clone()));
658→                }
659→            }
660→
661→            let classification = crate::float_probe::classify(
662→                agreements,
663→                total_probes,
664→                crate::float_probe::AGREEMENT_THRESHOLD,
665→            );
666→            float_probe_results.push(crate::float_probe::FloatProbeResult {
667→                param_index: idx,
668→                param_name: analysis.params[idx].name.clone(),
669→                classification,
670→                agreements,
671→                total_probes,
672→                divergent_values,
673→            });
674→        }
675→    }
676→
677→    let float_bias = crate::float_probe::build_bias_map(&float_probe_results);
678→    let has_integer_treating = float_bias
679→        .values()
680→        .any(|c| *c == crate::float_probe::FloatClassification::IntegerTreating);
681→
682→    // --- User-provided candidate inputs (highest priority, no budget cap) ---
683→    let mut user_iter = config.user_seeds.iter().cloned().peekable();
684→
685→    // --- Literal-derived seed inputs ---
686→    // Execute extracted literals first to cover magic-value branches before random exploration.
687→    let literal_candidates = literals_to_candidate_inputs(&analysis.params, &analysis.literals);
688→    let literal_budget = literal_candidates
689→        .len()
690→        .min(config.max_iterations as usize / 2);
691→    let mut literal_iter = literal_candidates.into_iter().take(literal_budget).peekable();
692→
693→    // --- Candidate inputs (from --inputs or .shatter/ config) ---
694→    // Priority above pool seeds, below literal seeds.
695→    let candidate_budget = config
696→        .candidate_inputs
697→        .len()
698→        .min(config.max_iterations as usize / 3);
699→    let mut candidate_iter = config.candidate_inputs.iter().take(candidate_budget).cloned().peekable();
700→
701→    // --- Pool-derived seed inputs ---
702→    // Cross-function interesting values, injected after literals but before random generation.
703→    let pool_budget = config
704→        .pool_seeds
705→        .len()
706→        .min(config.max_iterations as usize / 4);
707→    let mut pool_iter = config.pool_seeds.iter().take(pool_budget).cloned().peekable();
708→
709→    let explore_start = Instant::now();
710→
711→    for _ in 0..config.max_iterations {
712→        if let Some(timeout) = config.timeout_explore
713→            && explore_start.elapsed() >= timeout
714→        {
715→            break;
716→        }
717→
718→        iterations += 1;
719→
720→        // --- Per-execution setup ---
721→        if per_execution_setup
722→            && let Some(ref setup_file) = config.setup_file
723→        {
724→            setup_context =
725→                send_setup(frontend, setup_file, &analysis.name, config.setup_mode, config.project_root.clone()).await?;
726→        }
727→
728→        // --- Input generation ---
729→        // Priority: user seeds → literals → candidate inputs → pool seeds → custom generators → random.
730→        let inputs = if let Some(user_inputs) = user_iter.next() {
731→            user_inputs
732→        } else if let Some(lit_inputs) = literal_iter.next() {
733→            lit_inputs
734→        } else if let Some(cand_inputs) = candidate_iter.next() {
735→            cand_inputs
736→        } else if let Some(pool_inputs) = pool_iter.next() {
737→            pool_inputs
738→        } else if use_generators {
739→            generate_inputs_with_custom(
740→                &analysis.params,
741→                &config.value_sources,
742→                &mut prefetched,
743→                &mut rng,
744→                Some(&config.capabilities),
745→            )
746→        } else if has_integer_treating {
747→            crate::input_gen::generate_random_inputs_with_float_bias(
748→                &analysis.params,
749→                &float_bias,
750→                &mut rng,
751→                None,
752→            )
753→        } else {
754→            generate_random_inputs(&analysis.params, &mut rng, None)
755→        };
756→
757→        let response = frontend
758→            .send(ProtoCommand::Execute {
759→                function: analysis.name.clone(),
760→                inputs: inputs.clone(),
761→                mocks: config.mocks.clone(),
762→                setup_context: setup_context.clone(),
763→            })
764→            .await?;
765→
766→        let exec_result = match response.result {
767→            ResponseResult::Execute(result) => *result,
768→            ResponseResult::Error { code, message, .. } => {
769→                return Err(ExploreError::UnexpectedResponse(format!(
770→                    "execute error ({code:?}): {message}"
771→                )));
772→            }
773→            other => {
774→                return Err(ExploreError::UnexpectedResponse(format!("{other:?}")));
775→            }
776→        };
777→
778→        // --- Per-execution teardown ---
779→        if per_execution_setup && frontend_supports(&config.capabilities, "teardown") {
780→            send_teardown(frontend, &analysis.name).await?;
781→        }
782→
783→        for &line in &exec_result.lines_executed {
784→            all_lines.insert(line);
785→        }
786→
787→        let hash = path_hash(&exec_result, &config.loop_buckets);
788→        *path_counts.entry(hash).or_insert(0) += 1;
789→        let is_new = seen_paths.insert(hash);
790→
791→        // Track per-branch discovery attribution.
792→        for decision in &exec_result.branch_path {
793→            if seen_branch_ids.insert(decision.branch_id) {
794→                discoveries.push((decision.branch_id, DiscoveryMethod::Random));
795→            }
796→        }
797→
798→        if is_new {
799→            let error_intent = classify_error_intent(&exec_result);

798→        if is_new {
799→            let error_intent = classify_error_intent(&exec_result);
800→            new_path_executions.push(ExecutionSummary {
801→                inputs: inputs.clone(),
802→                return_value: exec_result.return_value.clone(),
803→                thrown_error: exec_result
804→                    .thrown_error
805→                    .as_ref()
806→                    .map(|e| format!("{}: {}", e.error_type, e.message)),
807→                lines_executed: exec_result.lines_executed.clone(),
808→                is_new_path: true,
809→                error_intent,
810→            });
811→        }
812→
813→        raw_results.push((inputs, exec_result));
814→    }
815→
816→    // --- Per-function teardown ---
817→    if per_function_setup && frontend_supports(&config.capabilities, "teardown") {
818→        send_teardown(frontend, &analysis.name).await?;
819→    }
820→
821→    let total_lines = instrumentable_line_count
822→        .unwrap_or_else(|| analysis.end_line.saturating_sub(analysis.start_line) + 1);
823→
824→    Ok(ObservationOutput {
825→        function_name: analysis.name.clone(),
826→        iterations,
827→        unique_paths: seen_paths.len(),
828→        lines_covered: all_lines.len(),
829→        total_lines,
830→        new_path_executions,
831→        raw_results,
832→        discoveries,
833→        nondeterministic_fields: vec![],
834→        float_probe_results,
835→    })
836→}
